---@class LBattleProcess
local LBattleProcess = classX("LBattleProcess", nil)

local _Process_Step = {
    Abort = -2,
    Error = -1,
    None = 0,
    SaveFormation = 1,
    ReqCombat = 2,
    ReportCreate = 3, --等待战报结束
    ReportGetter = 4,
    ReportFinished = 5,
    Playing = 6, --正在播放
    ReqResult = 7,--请求结算，后端结算结果
    Done = 99,
}

local _TimeCheckStepMap = {
    [_Process_Step.SaveFormation] = true,
    [_Process_Step.ReqCombat] = true,
    [_Process_Step.ReportCreate] = true,
}

---需要提示操作繁忙的步骤
local _NotReplaceStepMap = {
    [_Process_Step.SaveFormation] = true,
    [_Process_Step.ReqCombat] = true,
    [_Process_Step.ReportCreate] = true,
    [_Process_Step.ReportGetter] = true,
}

local _reqIndex = 0
local MakeReqIndex = function ()
    local idx = _reqIndex + 1
    if idx > 2147483647 then
        idx = 1
    end
    _reqIndex = idx
    return idx
end


function LBattleProcess:ctor(battleType)
    ---@type number 战斗类型
    self.battleType = battleType

    ---@type V_Battle_BattleConfig 战斗请求配置
    self.battleConfig = nil

    ---@type LFightReportGetter 战报请求器
    self.reportGetter = nil

    ---@type LFightReportData 战报
    self.reportData = nil

    ---@type string 战报id
    self.reportId = ""
    ---@type string 战报请求key
    self.requestReportId = ""

    ---@type number 请求保存阵形时的匹配序号
    self.formationReqIndex = 0

    ---@type number 当前流程进度
    self._step = _Process_Step.None
    ---@type number 步骤开始时间
    self._stepTime = 0
    ---@type number 步骤超时时间
    self._stepTimeOut = 5
end

function LBattleProcess:ShowBattle()
    self._step = _Process_Step.Playing
    CtrlCenter.Battle:ShowBattle(self.battleConfig, self.reportData, self.battleConfig.isOpenWithoutView)
end

function LBattleProcess:TestShowBattle()
    self._step = _Process_Step.Playing
    CtrlCenter.Battle:ShowBattle(self.battleConfig, self.reportData, self.battleConfig.isOpenWithoutView)
end


function LBattleProcess:InitFromCombatResp(pb)
    local data = {
        combatType = pb.combatType,
        battleType = pb.combatType,
        startTime = tonumber(pb.startTime),
        targetName = pb.targetName,
        targetLevel = pb.targetLevel,
        monsterId = pb.monsterId,
        serverId = pb.serverId,
        refId = pb.refId,
        addCostId = pb.addCostId,
        multReportIds = pb.multReportIds,
        activityData = pb.activityData,
    }
    self._combatRespData = data
end

function LBattleProcess:CheckCanStartProcess()
    if _NotReplaceStepMap[self._step] then
        return false
    end
    return true
end

function LBattleProcess:StartProcessBattle(isNeedSaveFormation)
    local config = self.battleConfig
    local battleType = self.battleType
    local index = config.index or 1
    local isTestBattle = config.isTestBattle
    local reportUrl = config.reportUrl
    local reportJson = config.reportJson

    local step = self._step
    if step == _Process_Step.ReportFinished then
        self:ShowBattle()
        return true
    else
        if _NotReplaceStepMap[self._step] then
            ---提示有相同战斗在进行
            ShowSysMsg(I18nText(2078))
            return false
        end
        ---新战斗，开始步骤
        if reportJson then
            local jsonReportData = ModuleCenter.Battle:NewBattleReport(reportJson.id)
            jsonReportData:InitData(reportJson)
            self.reportData = jsonReportData
            self.reportData:AttachProcess(self)
            self:StepReportFinished()
        elseif not string.isempty(reportUrl) then
            self.reportId = reportUrl
            self:StepReportGetter()
        else
            if isNeedSaveFormation then
                self:StepFormation()
            else
                self:StepReqCombat()
            end
        end
    end

    FireEvent(EventNames.BATTLE_PROCESS_START, battleType)

    return true

end

function LBattleProcess:SetBattleConfig(battleConfig)
    self.battleConfig = battleConfig
end

function LBattleProcess:StepFormation()
    self._step = _Process_Step.SaveFormation
    self._stepTime = Time.realtimeSinceStartup
    self.formationReqIndex = MakeReqIndex()
    CtrlCenter.Battle:SaveFormation(self.battleType, self.formationReqIndex)
end

function LBattleProcess:StepReqCombat()
    self._step = _Process_Step.ReqCombat

    local config = self.battleConfig
    local battleType = self.battleType
    local index = config.index or 1
    local isTestBattle = config.isTestBattle
    local params = nil
    if config.params then
        params = config.params
    elseif config.monsterRefId then
        params = {monster = config.monsterRefId}
    end
    local formation1 = ModuleCenter.Battle:GetFormation(battleType, index)
    if isTestBattle then
        -- 测试战斗防止报错
        if not config.formation2 then
            ---@type LxFormationObj
            local newFormation2 = ModuleCenter.Battle:NewFormation()
            newFormation2.order = 1
            newFormation2.power = 0
            for i, v in pairs(formation1.positions) do
                if v:IsHero() then
                    ---@type LxHeroObj
                    local heroObj = ModuleCenter.Hero:GetHero(v.id)
                    local heroPosObj = newFormation2:AddHeroPos(v.index, heroObj)
                    heroPosObj.id = tostring(i)
                end
            end
            config.formation2 = newFormation2
        end
        params = {atkFormation=config.formation1, defFormation=config.formation2}
    else
        if config.isReliefTroop then
            params = params or {}
            params.atkFormation = config.formation1
            params.relFormation = config.relFormation
        end
    end

    self._stepTime = Time.realtimeSinceStartup
    HandlerCenter.Battle:CombatReq(self.battleType, params)
end

---@param reportData LFightReportData
function LBattleProcess:FillVideoParam(reportData)
    reportData.battleType = self.battleType
    reportData.combatType = self.battleType
    local formationAName = self.battleConfig.formationAName
    if not string.isempty(formationAName) then
        reportData.formationA.formationName = formationAName
    end
    local formationBName = self.battleConfig.formationBName
    if not string.isempty(formationBName) then
        reportData.formationB.formationName = formationBName
    end
end
function LBattleProcess:StepReportGetter()
    self._step = _Process_Step.ReportGetter

    if self.battleType == BattleType.Video then
        CtrlCenter.Battle:StartTextAssetReportGetter(self.reportId, function(isOk, reportData)
            ---本地资源的录像战报记录的战斗类型可能各种各样，全部强制改为指定类型
            self:FillVideoParam(reportData)

            self:OnReportGetterCallback(isOk, reportData)
        end)
    else
        CtrlCenter.Battle:StartReportGetter(self.battleConfig.serverId, self.reportId, function(isOk, reportData)
            self:OnReportGetterCallback(isOk, reportData)
        end)
    end

end

function LBattleProcess:OnReportGetterCallback(isOk, reportData)
    if self:IsDisposed() then return end
    if self._step ~= _Process_Step.ReportGetter then
        return
    end
    if not isOk then
        self:StepError()
        return
    end
    self.reportData = reportData
    if self._combatRespData then
        self.reportData:InitFromCombatResp(self._combatRespData)
    end
    self.reportData:AttachProcess(self)
    self:StepReportFinished()
end

function LBattleProcess:StepReportFinished()
    self._step = _Process_Step.ReportFinished
    self:ShowBattle()
end

---战斗流程错误
function LBattleProcess:StepError()
    self._step = _Process_Step.Error
    if not self.battleConfig.isOpenWithoutView then
        local battleMgr = CtrlCenter.Battle:GetBattleMgr()
        local battleView = battleMgr:GetBattleView()
        if battleView and not battleView:IsFormationEdit() and battleView:GetBattleType() == self.battleType and MgrCenter.LevelMgr:IsInLevel(LevelNames.Battle) then
            self:ShowErrorAlert()
        end
    end
    FireEvent(EventNames.BATTLE_PROCESS_END, self.battleType)
end

function LBattleProcess:OnFormationFinish()
    if self._step ~= _Process_Step.SaveFormation then
        return
    end
    self:StepReqCombat()
end

function LBattleProcess:ShowErrorAlert()
    ShowAlert({
        refId = 3015,
        actionClose = function()
            if self._isDisposed then
                return
            end
            CtrlCenter.Battle:LeaveBattle(self.battleConfig)
        end
    })
end


function LBattleProcess:OnReqCombatFinish(pb)
    if self._step ~= _Process_Step.ReqCombat then
        return
    end
    local errCode = pb.errCode
    if errCode > 0 then
        local errorMsg = I18nError(tonumber(errCode))
        if not string.isempty(errorMsg) then
            ShowSysMsg(errorMsg)
        end
        self:StepError()
        return
    end
    self.reportId = pb.reportId
    self:InitFromCombatResp(pb)
    self._step = _Process_Step.ReportCreate
end

function LBattleProcess:StartOfflineBattle(pb)
    self._step = _Process_Step.ReqCombat
    self.battleType = pb.combatType
    self.battleConfig = {
        battleType = self.battleType,
        isOpenWithoutView = true,
    }
    self:OnReqCombatFinish(pb)
    if LOG_INFO_ENABLED then
        printInfo("battle", "离线战斗恢复, 战斗类型 : %s， 战报Id：%s", tostring(self.battleType), tostring(self.reportId))
    end
    self:StepReportGetter()
end

function LBattleProcess:OnBattleReportCreateFinish(reportId)
    if self._step ~= _Process_Step.ReportCreate then
        return
    end
    if self.reportId ~= reportId then
        return
    end
    self:StepReportGetter()
end

function LBattleProcess:CheckTimeOut()
    local isCheck =  _TimeCheckStepMap[self._step]
    if not isCheck then
        return false
    end
    local passTime = Time.realtimeSinceStartup - self._stepTime
    return passTime > self._stepTimeOut
end

function LBattleProcess:CheckResendReqResult()
    if self._step == _Process_Step.ReqResult then
        if LOG_INFO_ENABLED then
            printInfo("battle", "断线重连战斗结算请求，战斗类型： %s, 战报id:%s", tostring(self.battleType),tostring(self.reportId))
        end
        self:StepBattleResultRequest()
    end
end

function LBattleProcess:CheckResendReqCombat()
    if self._step == _Process_Step.ReqCombat then
        if LOG_INFO_ENABLED then
            printInfo("battle", "断线重连战斗开始请求，战斗类型 : %s", tostring(self.battleType))
        end
        self:StepReqCombat()
    end
end

function LBattleProcess:StepBattleResultRequest()
    self._step = _Process_Step.ReqResult
    HandlerCenter.Battle:OnCombatResultReq(self.reportId, self.battleType)
end

function LBattleProcess:OnBattleResultFinish(pb)
    self._step = _Process_Step.Done
    if self.reportData then
        self.reportData:SetBattleResult(pb)
        CtrlCenter.Battle:ShowBattleResult(self.reportData, self.battleConfig)
    end
    FireEvent(EventNames.BATTLE_PROCESS_END, self.battleType)
end

---中止进程
function LBattleProcess:Abort()
    self._step = _Process_Step.Abort
end

function LBattleProcess:IsValid()
    if self._isDisposed then
        return false
    end
    return self._step >= 0
end

function LBattleProcess:IsBattleInBackground()
    return self.battleConfig and self.battleConfig.isOpenWithoutView or false
end

function LBattleProcess:IsLive()
    if self._step >= 0 and self._step < _Process_Step.Done and not self:CheckTimeOut() then
        return true
    end
    return false
end

function LBattleProcess:IsCanReplace()
    if self._isDisposed then
        return true
    end

    if self._step <= 0 or self._step >= _Process_Step.Done then
        return true
    end

    if self:CheckTimeOut() then
        return true
    end

    if self.battleType >= BattleType.Video then
        ---录像播放可以随便替换
        return true
    end

    return false
end

function LBattleProcess:IsDisposed()
    return self._isDisposed
end

function LBattleProcess:Dispose()
    if self._isDisposed then return end

    if self.reportGetter then
        self.reportGetter:Dispose()
    end

    table.dispose(self)

    self._isDisposed = true
end

return LBattleProcess